import { GoogleGenAI, Type } from "@google/genai";
import { ScriptParts, ScriptPartKey } from "../types";
import { getAiClient } from "./keyService";

const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Phân tích và "tách" trang phục.
 */
export const describeKocOutfit = async (outfitPart: any): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    Analyze the CLOTHING in this image in extreme detail for an AI image generator.
    !!! CRITICAL PRIVACY & IDENTITY RULE !!!: 
    - Focus ONLY on the garments, fabric, shoes, and accessories. 
    - COMPLETELY IGNORE the person's face, ethnicity, hair, and identity. 
    Return a concise technical fashion paragraph in English.
  `;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, { inlineData: outfitPart }] }
    });
    return response.text?.trim() || "A stylish outfit.";
  } catch (error) { return "Detailed fashion outfit."; }
};

/**
 * Tạo kịch bản TikTok với NGUYÊN TẮC CỘNG ĐỒNG nghiêm ngặt.
 * CƯỠNG ÉP ĐỘ DÀI: 160 - 190 ký tự.
 */
export const generateKocScript = async (
  imageParts: any[], productName: string, keyword: string, scriptTone: string,
  productSize: string, scriptNote: string, scriptLayout: string, gender: string, voice: string,
  sceneCount: number
): Promise<ScriptParts> => {
  const ai = getAiClient();

  const FORBIDDEN_TERMS = `
    Facebook, Shopee, Lazada, Tiki, Zalo, QR, Chuyển khoản, Fanpage, Địa Chỉ, Số điện thoại, Nước Anh, Nước Pháp, Trung Quốc, Tên quốc gia, Dior, Gucci, Adidas, 
    Nike, giá rẻ, chốt, So sánh với các thương hiệu khác, Làm dày, Chống rụng, Kích thích mọc tóc, Làm hồng, Se Khít, Da đen, Đồ điên, Con thiểu năng, 
    Sale sốc, Mua ngay đi, Cam kết khẳng định, So sánh nhất, Top 1, Hàng đầu, Chính hãng, Độc quyền, Duy nhất, 100%, Tuyệt đối, 
    Chắc chắn, Giá rẻ nhất, Giá tốt nhất, Cam kết, Tốt nhất, Tức thì, Chất lượng nhất, Top 1 thế giới, Vĩnh viễn, Hoàn toàn, 
    Cam kết hiệu quả, Bảo hành trọn đời, Xả hàng, Từ ngữ liên quan điều trị, Y tế, Trị, Điều trị, Dứt điểm, Chữa khỏi, 
    Đánh bay, Hiệu quả, Loại bỏ, Phục hồi, Xóa bỏ, Giảm mỡ, Kem tan mỡ, Giảm kích thước các vòng, Làm săn chắc, Ngăn ngừa, Làm chậm tốc độ, 
    Dừng mọc lông, Bảo vệ da khỏi, Cam kết giao hàng, Khuyến mãi ảo, Công dụng quá đà, Gửi hàng 2 ngày nhận được, Nhận hàng không ưng trả lại, 
    Bỏ qua sẽ hối hận cả đời, Tặng miễn phí sản phẩm, Chia sẻ để mua hàng giá 0đ, Quà tặng miễn phí cho tất cả mọi người, Nhanh tay mua ngay để được giá ưu đãi tốt nhất, 
    Ấn vào Link để nhận thưởng miễn phí, Diệt mụn, Phòng chống nhiễm trùng, Ngăn chặn lão hóa, Làm đảo ngược tình trạng lão hóa, Giảm cân / Tăng cân, Tăng cường cảm xúc, 
    Hấp dẫn giới tính, Ưu đãi huỷ diệt, Khuyến Mãi cực sốc, Giảm giá kịch sàn, Thanh lý toàn bộ, Nhanh tay đặt hàng, Có 1 không 2,
    Em đang có, Xem này, Mã giảm sâu, Voucher, Tiktok.
  `;

  let dialectInstruction = voice === 'Miền Bắc' 
    ? `VĂN PHONG MIỀN BẮC (HÀ NỘI): dùng nhé, ạ, thế, đấy, chứ.` 
    : `VĂN PHONG MIỀN NAM (SÀI GÒN): dùng nha, nè, nghen, thiệt, hông, vầy.`;

  const prompt = `
    Trong vai 1 Creator chuyên tạo video viral hãy tạo kịch bản bán hàng cho "${productName}". USP: "${keyword}". Layout: "${scriptLayout}". Giới tính: ${gender}.
    YÊU CẦU: Đúng ${sceneCount} phần (v1..v${sceneCount}). KHÔNG nhắc bối cảnh/địa điểm.

    !!! QUAN TRỌNG NHẤT (STRICT LENGTH RULE) !!!:
    Mỗi phần kịch bản (v1, v2...) BẮT BUỘC PHẢI CÓ ĐỘ DÀI TỪ 160 ĐẾN 190 KÝ TỰ. 
    - Tuyệt đối KHÔNG ĐƯỢC NGẮN HƠN 160 ký tự.
    - Tuyệt đối KHÔNG ĐƯỢC DÀI HƠN 190 ký tự.
    - Nếu câu quá ngắn, hãy thêm các tính từ miêu tả cảm xúc hoặc các từ đệm địa phương.
    ${dialectInstruction}
    Kịch bản phải bắt đầu bằng một câu hỏi nhức nhối.

    !!! CẢNH BÁO VI PHẠM CỘNG ĐỒNG - TUYỆT ĐỐI KHÔNG SỬ DỤNG CÁC TỪ SAU !!!:
    ${FORBIDDEN_TERMS}
  `;

  const properties: Record<string, any> = {};
  const required: string[] = [];
  for (let i = 1; i <= sceneCount; i++) {
    const key = `v${i}`;
    properties[key] = { type: Type.STRING };
    required.push(key);
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.OBJECT, properties, required }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (e) {
    const fallback: ScriptParts = {};
    for (let i = 1; i <= sceneCount; i++) fallback[`v${i}`] = '';
    return fallback;
  }
};

/**
 * Tạo hình ảnh với TUÂN THỦ TUYỆT ĐỐI GHI CHÚ NHÂN VẬT & SẢN PHẨM.
 */
export const generateKocImage = async (
  referenceImageParts: any[], 
  faceImagePart: any | null, 
  outfitImagePart: any | null,
  outfitDescription: string, 
  productName: string,
  scriptPart: string, 
  characterDescription: string, 
  userCustomPrompt: string | undefined, 
  gender: string, 
  imageStyle: 'Realistic' | '3D' = 'Realistic', 
  backgroundNote: string = "",
  visualNote: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  // MANDATORY LIFESTYLE STYLE GUIDELINES
  const lifestyleStyle = "Natural lifestyle shot, daily usage scenario, candid photography, realistic soft natural lighting, casual environment.";

  const baseStyle = is3D 
    ? `High-quality 3D Animation Pixar/Disney style, ${lifestyleStyle} vibe, vibrant but natural colors, expressive character, polished CGI.`
    : `Photorealistic RAW PHOTO, ${lifestyleStyle}, 8k resolution, authentic skin textures, cinematic but realistic natural lighting.`;

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "không xuất hiện sản phẩm", "bỏ sản phẩm", "không thấy sản phẩm", "no product", "remove product", "without product"];
  const isNoProductRequested = userCustomPrompt && noProductKeywords.some(kw => userCustomPrompt.toLowerCase().includes(kw));

  const visualRules = `
    CRITICAL VISUAL RULES (STRICT NO-TEXT POLICY):
    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS.
    2. The background must be CLEAN and FREE of signage, posters, labels, or written words.
    3. NO UI elements, NO speech bubbles, NO watermarks, NO subtitles.
    4. The image must look like a CANDID MOMENT from a real KOC video.

    CRITICAL RESTRICTIONS & RULES: 
    1. NO CHILDREN, NO KIDS. The subject must be an adult.
    2. ${is3D ? "Must look like high-quality 3D CGI with a lifestyle feel." : "Must look like a real, natural lifestyle photo."}
    ${isNoProductRequested ? '3. ABSOLUTELY NO PRODUCT/DEVICE IN THIS IMAGE.' : `
    3. STRICT PRODUCT FIDELITY (MANDATORY):
       - The product "${productName}" MUST MATCH the input reference image 1:1.
       - DAILY USAGE: Show the product naturally in its intended environment.
       - PRESERVE PATTERNS & TEXTURES: Logo and design must be preserved.
       - CONSISTENT SCALE: Maintain the same product-to-character ratio across all scenes.
       - LOCK the product appearance exactly to the original photo provided.`}
  `;

  const characterFidelityRule = `
    !!! CRITICAL CHARACTER FIDELITY (PRIORITY) !!!:
    Follow these instructions: "${characterDescription}".
    Gender: Adult Vietnamese ${gender}.
    - MANDATORY: If description mentions body type or clothing style, apply it 100%. 
  `;

  const identityRule = faceImagePart 
    ? `IDENTITY: Transfer EXACT facial features/hair from FACE_REFERENCE. Must look natural and relaxed.`
    : `IDENTITY: Adult Vietnamese ${gender} matching the character description mandate.`;

  const outfitRule = outfitImagePart ? `
    OUTFIT: Use textures and style from "${outfitDescription}". Casual/daily fashion.
  ` : "";

  const sceneInstruction = `SCENE: Character in a natural ${backgroundNote || 'daily lifestyle setting'}. Context: "${scriptPart}". Action should feel spontaneous and unposed.`;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16. 
    ${characterFidelityRule}
    ${identityRule}
    ${outfitRule}
    ${visualRules}
    ${visualNote ? `VISUAL COMPOSITION: ${visualNote}.` : ""}
    ${sceneInstruction} 
    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (faceImagePart) contents.push({ inlineData: faceImagePart });
  if (outfitImagePart) contents.push({ inlineData: outfitImagePart });
  if (!isNoProductRequested && referenceImageParts.length > 0) contents.push({ inlineData: referenceImageParts[0] });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

/**
 * Generates a video prompt for VEO-3 model based on script and visual context.
 */
export const generateKocVeoPrompt = async (
  productName: string, 
  scriptText: string, 
  gender: string, 
  voice: string,
  productImageBase64?: string,
  generatedImageBase64?: string,
  isNoProductRequested: boolean = false,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const voiceTag = voice === 'Miền Bắc' ? 'Northern Vietnamese' : 'Southern Vietnamese';
  const voiceGender = gender === 'Nữ' ? 'Female' : 'Male';

  const productInteractionRule = isNoProductRequested
    ? `PHẦN 2: HÀNH ĐỘNG (LIFESTYLE):
      - Nhân vật đang tương tác tự nhiên trong không gian sống. TUYỆT ĐỐI KHÔNG xuất hiện sản phẩm "${productName}".
      - Cách nhân vật di chuyển, nói chuyện và biểu cảm chân thực. Kịch bản: "${scriptText}".`
    : `PHẦN 2: HÀNH ĐỘNG (LIFESTYLE):
      - Nhân vật đang cầm trên tay và sử dụng sản phẩm "${productName}" một cách tự nhiên trong đời thường.
      - Chuyển động nhẹ nhàng, thoải mái. Kịch bản: "${scriptText}".
      - [SẢN PHẨM PHẢI GIỐNG ẢNH THAM CHIẾU 100%, KHÔNG BIẾN DẠNG]`;

  const instructionPrompt = `
  Nhiệm vụ: Viết Prompt chi tiết cho video AI (VEO-3) dài 8 giây theo phong cách LIFESTYLE SHOT.
  PHONG CÁCH: ${is3D ? "3D Animation / CGI Style but realistic movements" : "Natural Lifestyle / Candid Real Life Style"}.

  CẤU TRÚC PROMPT:
  PHẦN 1: NHÂN VẬT & DIỆN MẠO. Nhân vật người Việt Nam. Vẻ ngoài đời thường, gần gũi.
  ${productInteractionRule}
  PHẦN 3: BỐI CẢNH & ÁNH SÁNG. Không gian sử dụng thực tế (phòng bếp, phòng khách, quán cafe...). Ánh sáng tự nhiên.
  PHẦN 4: CHUYỂN ĐỘNG MÁY ẢNH (9:16). Chuyển động máy tự nhiên như quay bằng điện thoại (handheld feel) hoặc dolly mượt mà.
  PHẦN 5: LỜI THOẠI: ✨ Model speaks in ${voiceTag} voice (${voiceGender}): "${scriptText}"
  PHẦN 6: CHẤT LƯỢNG: 4K, 60fps, Natural Colors, ${is3D ? "Masterpiece CGI" : "Photorealistic"}.

  YÊU CẦU: Trả về 1 dòng Tiếng Anh duy nhất (trừ phần lời thoại). Không xuống dòng.`;

