export const describeKocOutfit = async (outfitPart: any): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    Analyze the CLOTHING in this image in extreme detail for an AI image generator.
    !!! CRITICAL PRIVACY & IDENTITY RULE !!!: 
    - Focus ONLY on the garments, fabric, shoes, and accessories. 
    - COMPLETELY IGNORE the person's face, ethnicity, hair, and identity. 
    Return a concise technical fashion paragraph in English.
  `;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, { inlineData: outfitPart }] }
    });
    return response.text?.trim() || "A stylish outfit.";
  } catch (error) { return "Detailed fashion outfit."; }
};

/**
 * Tạo kịch bản TikTok với 45 CHIẾN THUẬT HOOK.
 */
export const generateKocScript = async (
  imageParts: any[], productName: string, keyword: string, scriptTone: string,
  productSize: string, scriptNote: string, scriptLayout: string, gender: string, voice: string,
  sceneCount: number
): Promise<ScriptParts> => {
  const ai = getAiClient();

  const FORBIDDEN_TERMS = `Facebook, Shopee, Lazada, Tiki, Zalo, QR, Chuyển khoản, Fanpage, Địa Chỉ, Số điện thoại, Dior, Gucci, Adidas, Nike, giá rẻ, chốt, Sale sốc, Mua ngay đi, Cam kết, Tốt nhất, 100%, Tuyệt đối.`;

  let dialectInstruction = voice === 'Miền Bắc' 
    ? `VĂN PHONG MIỀN BẮC (HÀ NỘI): dùng nhé, ạ, thế, đấy, chứ.` 
    : `VĂN PHONG MIỀN NAM (SÀI GÒN): dùng nha, nè, nghen, thiệt, hông, vầy.`;

  const prompt = `
    Bạn là một Creative Director bậc thầy về Video Viral. 
    Nhiệm vụ: Tạo kịch bản ${sceneCount} cảnh cho sản phẩm "${productName}". 
    USP: "${keyword}". Layout: "${scriptLayout}". Giới tính: ${gender}.

    !!! YÊU CẦU QUAN TRỌNG VỀ HOOK (CẢNH v1) !!!:
    Phần mở đầu (v1) BẮT BUỘC phải áp dụng 1 trong 45 chiến thuật Hook sau đây một cách sáng tạo và phù hợp nhất với sản phẩm:
    ${MASTER_HOOK_STRATEGIES}

    !!! YÊU CẦU ĐỘ DÀI VÀ VĂN PHONG !!!:
    - Mỗi phần (v1..v${sceneCount}) BẮT BUỘC PHẢI TỪ 160 ĐẾN 190 KÝ TỰ. 
    - ${dialectInstruction}
    - KHÔNG nhắc bối cảnh/địa điểm trong lời thoại.
    - Cảnh v1 phải cực kỳ bắt tai (Catchy).

    !!! CẤM SỬ DỤNG CÁC TỪ VI PHẠM !!!:
    ${FORBIDDEN_TERMS}
  `;

  const properties: Record<string, any> = {};
  const required: string[] = [];
  for (let i = 1; i <= sceneCount; i++) {
    const key = `v${i}`;
    properties[key] = { type: Type.STRING };
    required.push(key);
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.OBJECT, properties, required }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (e) {
    const fallback: ScriptParts = {};
    for (let i = 1; i <= sceneCount; i++) fallback[`v${i}`] = '';
    return fallback;
  }
};

/**
 * Tạo hình ảnh Lifestyle shot - Natural daily usage.
 */
export const generateKocImage = async (
  referenceImageParts: any[], faceImagePart: any | null, outfitImagePart: any | null,
  outfitDescription: string, productName: string, scriptPart: string, characterDescription: string, 
  userCustomPrompt: string | undefined, gender: string, imageStyle: 'Realistic' | '3D' = 'Realistic', 
  backgroundNote: string = "", visualNote: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  const lifestyleStyle = "Natural lifestyle shot, daily usage scenario, candid photography, realistic soft natural lighting, casual environment.";
  const baseStyle = is3D 
    ? `High-quality 3D Animation Pixar style, ${lifestyleStyle} vibe, vibrant but natural colors.`
    : `Photorealistic RAW PHOTO, ${lifestyleStyle}, 8k, authentic skin textures, realistic natural lighting.`;

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "không xuất hiện sản phẩm", "bỏ sản phẩm", "không thấy sản phẩm", "no product", "remove product", "without product"];
  const isNoProductRequested = userCustomPrompt && noProductKeywords.some(kw => userCustomPrompt.toLowerCase().includes(kw));

  const visualRules = `
    CRITICAL VISUAL RULES:
    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS.
    2. CLEAN background. NO UI, NO speech bubbles, NO watermarks.
    3. NO CHILDREN.
    ${isNoProductRequested ? '3. ABSOLUTELY NO PRODUCT/DEVICE IN THIS IMAGE.' : `
    4. STRICT PRODUCT FIDELITY: Product "${productName}" MUST MATCH reference 1:1. Consistent scale.`}
  `;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16. 
    CHARACTER: Vietnamese Adult ${gender}. ${characterDescription}.
    ${faceImagePart ? 'IDENTITY: Use FACE_REFERENCE.' : ''}
    ${outfitImagePart ? `OUTFIT: ${outfitDescription}.` : ''}
    ${visualRules}
    SCENE: "${scriptPart}". ${backgroundNote}. ${visualNote}. ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (faceImagePart) contents.push({ inlineData: faceImagePart });
  if (outfitImagePart) contents.push({ inlineData: outfitImagePart });
  if (!isNoProductRequested && referenceImageParts.length > 0) contents.push({ inlineData: referenceImageParts[0] });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

export const generateKocVeoPrompt = async (
  productName: string, scriptText: string, gender: string, voice: string,
  productImageBase64?: string, generatedImageBase64?: string, isNoProductRequested: boolean = false,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const voiceTag = voice === 'Miền Bắc' ? 'Northern Vietnamese' : 'Southern Vietnamese';
  const instructionPrompt = `
  TASK: Write 8s AI Video Prompt (VEO-3) for Lifestyle KOC Review.
  STYLE: ${imageStyle === '3D' ? "3D Animation CGI but realistic movements" : "Natural Lifestyle / Candid"}.
  PHẦN 1: Nhân vật người Việt Nam.
  PHẦN 2: HÀNH ĐỘNG: ${isNoProductRequested ? 'KHÔNG xuất hiện sản phẩm' : `Nhân vật tương tác với sản phẩm ${productName}`}.
  PHẦN 5: LỜI THOẠI: ✨ Model speaks in ${voiceTag} voice: "${scriptText}"
  YÊU CẦU: Trả về 1 dòng Tiếng Anh duy nhất.`;

  const contents: any[] = [{ text: instructionPrompt }];
  if (productImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: productImageBase64.split(',')[1] || productImageBase64 } });
  if (generatedImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });

  try {
    const response = await ai.models.generateContent({ model: "gemini-3-flash-preview", contents: { parts: contents } });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) { return ""; }
};

