    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS.
    2. CLEAN background. NO UI, NO speech bubbles, NO watermarks.
    3. NO CHILDREN or babies.
    4. The scene must look like a real-life candid moment, not a studio setup.
    ${isNoProductRequested ? '5. ABSOLUTELY NO PRODUCT/DEVICE IN THIS IMAGE.' : `
    5. STRICT PRODUCT FIDELITY: Product "${productName}" MUST MATCH reference 1:1. Consistent scale and design.`}
  `;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16. 
    CHARACTER: Vietnamese Adult ${gender}. ${characterDescription}.
    ${faceImagePart ? 'IDENTITY: Transfer facial features from face reference provided.' : ''}
    ${outfitImagePart ? `OUTFIT: Wear the garments from outfit reference (${outfitDescription}).` : ''}
    ${visualRules}
    SCENE: In a natural ${backgroundNote || 'daily setting'}. Action: "${scriptPart}". 
    VISUAL COMPOSITION: ${visualNote}. 
    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (faceImagePart) contents.push({ inlineData: faceImagePart });
  if (outfitImagePart) contents.push({ inlineData: outfitImagePart });
  if (!isNoProductRequested && referenceImageParts.length > 0) contents.push({ inlineData: referenceImageParts[0] });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

/**
 * Generates a video prompt for VEO-3 model.
 */
export const generateKocVeoPrompt = async (
  productName: string, 
  scriptText: string, 
  gender: string, 
  voice: string,
  productImageBase64?: string,
  generatedImageBase64?: string,
  isNoProductRequested: boolean = false,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const voiceTag = voice === 'Miền Bắc' ? 'Northern Vietnamese' : 'Southern Vietnamese';
  const instructionPrompt = `
  TASK: Write 8s AI Video Prompt (VEO-3) for Lifestyle KOC Review.
  STYLE: ${imageStyle === '3D' ? "3D Animation CGI but realistic movements" : "Natural Lifestyle / Candid Real Life"}.
  PHẦN 1: Nhân vật người Việt Nam. Vẻ ngoài đời thường.
  PHẦN 2: HÀNH ĐỘNG: ${isNoProductRequested ? 'KHÔNG xuất hiện sản phẩm' : `Nhân vật tương tác tự nhiên với sản phẩm ${productName}`}.
  PHẦN 3: BỐI CẢNH: Không gian sống thực tế, ánh sáng tự nhiên.
  PHẦN 5: LỜI THOẠI: ✨ Model speaks in ${voiceTag} voice: "${scriptText}"
  YÊU CẦU: Trả về 1 dòng Tiếng Anh duy nhất (trừ phần lời thoại).`;

  const contents: any[] = [{ text: instructionPrompt }];
  if (productImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: productImageBase64.split(',')[1] || productImageBase64 } });
  if (generatedImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });

  try {
    const response = await ai.models.generateContent({ model: "gemini-3-flash-preview", contents: { parts: contents } });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) { return ""; }
};

