                  <input type="text" value={state.productName} onChange={e => setState(p => ({ ...p, productName: e.target.value }))} placeholder="Nhập tên sản phẩm..." className="w-full p-3 border rounded-xl focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all font-bold" />
                </div>
                <div className="space-y-1">
                  <label className="block text-[10px] font-black text-slate-500 uppercase px-1">Keyword / USP chính</label>
                  <input type="text" value={state.keyword} onChange={e => setState(p => ({ ...p, keyword: e.target.value }))} placeholder="Ví dụ: Da trắng bật tông..." className="w-full p-3 border rounded-xl focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all font-bold" />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="block text-[10px] font-black text-slate-500 uppercase px-1">Giới tính KOC</label>
                  <select value={state.gender} onChange={e => setState(p => ({ ...p, gender: e.target.value }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none font-bold">
                    <option value="Nữ">Nữ</option>
                    <option value="Nam">Nam</option>
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="block text-[10px] font-black text-slate-500 uppercase px-1">Vùng miền</label>
                  <select value={state.voice} onChange={e => setState(p => ({ ...p, voice: e.target.value }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none font-bold">
                    <option value="Miền Bắc">Miền Bắc</option>
                    <option value="Miền Nam">Miền Nam</option>
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="block text-[10px] font-black text-slate-500 uppercase px-1">Thời lượng (Lifestyle scenes)</label>
                  <select value={state.sceneCount} onChange={e => setState(p => ({ ...p, sceneCount: parseInt(e.target.value) }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none font-black text-orange-600">
                    {SCENE_COUNT_OPTIONS.map(opt => (
                      <option key={opt.count} value={opt.count}>{opt.label}</option>
                    ))}
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="block text-[10px] font-black text-slate-500 uppercase px-1">Phong cách ảnh (Chốt: Lifestyle)</label>
                  <div className="flex bg-slate-50 p-1 rounded-xl border border-slate-200">
                    <button
                      onClick={() => setState(p => ({ ...p, imageStyle: 'Realistic' }))}
                      className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${state.imageStyle === 'Realistic' ? 'bg-orange-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
                    >
                      Người thật
                    </button>
                    <button
                      onClick={() => setState(p => ({ ...p, imageStyle: '3D' }))}
                      className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${state.imageStyle === '3D' ? 'bg-orange-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
                    >
                      3D Pixar
                    </button>
                  </div>
                </div>
              </div>
            </div>

            <div className="space-y-1">
              <label className="block text-[10px] font-black text-slate-500 uppercase px-1">Bố cục kịch bản (Layout)</label>
              <select value={state.scriptLayout} onChange={e => setState(p => ({ ...p, scriptLayout: e.target.value }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none font-medium text-sm">
                <option value="">-- Random Layout (Cưỡng ép Hook) --</option>
                {LAYOUT_OPTIONS.map(o => <option key={o} value={o}>{o}</option>)}
              </select>
            </div>

            <div className="space-y-1">
              <label className="block text-[10px] font-black text-slate-500 uppercase px-1">Ghi chú bối cảnh thực tế</label>
              <textarea
                value={state.scriptNote}
                onChange={e => setState(p => ({ ...p, scriptNote: e.target.value }))}
                placeholder="VD: Quán cafe tone nâu gỗ, phòng ngủ ánh sáng ấm..."
                className="w-full p-3 border rounded-xl h-20 text-sm focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all font-medium"
              />
            </div>

            <button onClick={handleGenerate} disabled={state.isGeneratingScript} className="w-full py-4 bg-orange-600 text-white font-black rounded-xl shadow-lg disabled:opacity-50 hover:bg-orange-700 transition-all active:scale-[0.98] uppercase tracking-widest text-sm">
              {state.isGeneratingScript ? "Đang xử lý kịch bản bộ..." : "Bắt đầu tạo kịch bản (45 Hook Mode)"}
            </button>
          </div>
        </div>
      </div>

      {state.script && (
        <div className="space-y-8 pb-32">
          <div className="bg-slate-900 p-6 rounded-2xl border border-slate-800 shadow-sm flex flex-col md:flex-row items-center justify-between gap-4">
            <div>
              <h3 className="text-sm font-black text-white uppercase tracking-tight">KẾT QUẢ CHIẾN DỊCH KOC LIFESTYLE</h3>
              <p className="text-[10px] font-bold text-orange-500 uppercase tracking-widest">
                {activeKeys.length} cảnh • {activeKeys.length * 8}s • {state.imageStyle === 'Realistic' ? 'Chân thực' : '3D Animation'}
              </p>
            </div>
            <div className="flex gap-3">
              <button onClick={downloadAllImages} className="px-5 py-2.5 bg-white text-slate-900 text-[10px] font-black rounded-xl uppercase tracking-widest hover:bg-slate-100 transition-all">Tải Ảnh (ZIP)</button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-6">
            {activeKeys.map((key, idx) => (
              <div key={key} className="space-y-4">
                <ScriptSection
                  title={idx === 0 ? `Hook Mở Đầu` : `Cảnh ${idx + 1}`}
                  content={state.script[key]}
                  color={idx === 0 ? "border-pink-500" : "border-orange-500"}
                  onChange={(val) => setState(p => ({ ...p, script: { ...p.script, [key]: val } }))}
                />
                <ImageCard
                  label={`Cảnh ${idx + 1}`}
                  imageData={state.images[key]}
                  videoPrompt={state.videoPrompts[key]}
                  onGeneratePrompt={() => handleGeneratePromptForKey(key)}
                  onRegenerate={() => handleGenImageForKey(key)}
                  onTranslate={() => { }}
                  customPrompt={state.images[key]?.customPrompt || ''}
                  onCustomPromptChange={(val) => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], customPrompt: val } } }))}
                />
              </div>
            ))}
          </div>

          <div className="flex flex-col items-center gap-6 py-12 border-t border-slate-200">
             <div className="flex flex-col md:flex-row gap-4 w-full justify-center">
                <button
                  onClick={handleBulkImage}
                  className="px-12 py-5 bg-orange-600 text-white font-black rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all text-sm flex items-center justify-center gap-4 uppercase tracking-widest"
                >
                  TỰ ĐỘNG TẠO TẤT CẢ ẢNH
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V5a2 2 0 00-2-2H4zm12 12H4l4-8 3 6 2-4 3 6z" clipRule="evenodd" /></svg>
                </button>
                <button
                  onClick={handleBulkPrompt}
                  className="px-12 py-5 bg-slate-900 text-white font-black rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all text-sm flex items-center justify-center gap-4 uppercase tracking-widest"
                >
                  TỰ ĐỘNG VIẾT TẤT CẢ PROMPTS
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14H11V21L20 10H13Z" /></svg>
                </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default KocReviewModule;
